function ag(a){const n=parseInt(a);if(n<=24)return"18-24";if(n<=34)return"25-34";if(n<=44)return"35-44";if(n<=54)return"45-54";if(n<=64)return"55-64";return"65+";}
function cp(nw,ds){const p=ds.percentiles,k=[10,20,30,40,50,60,70,80,90,95,99];if(nw<=0)return 5;if(nw<p[10])return Math.round((nw/p[10])*10);for(let i=0;i<k.length-1;i++){const lo=k[i],hi=k[i+1];if(nw>=p[lo]&&nw<p[hi])return Math.round(lo+((nw-p[lo])/(p[hi]-p[lo]))*(hi-lo));}return Math.round(99+Math.min((nw-p[99])/p[99],1)*0.9);}
function gl(p){return LBLS.find(l=>p>=l.min&&p<l.max)||LBLS[LBLS.length-1];}
function pm(s){return parseFloat(String(s).replace(/,/g,""))||0;}
function nm(nw,ds){const p=ds.percentiles,k=[10,20,30,40,50,60,70,80,90,95,99];for(const x of k)if(nw<p[x])return{p:x,amt:p[x],gap:p[x]-nw};return null;}
function fmt(n){if(n>=1000000)return"$"+(n/1000000).toFixed(1)+"M";if(n>=1000)return"$"+Math.round(n/1000)+"K";return"$"+n.toLocaleString("en-AU");}
function SourceBadge({s}){return(<div style={{flexShrink:0,width:200,boxSizing:"border-box",background:"#142133",border:`1px solid ${s.color}28`,borderRadius:14,padding:"14px",display:"flex",flexDirection:"column",gap:7,userSelect:"none",overflow:"hidden"}}><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{background:s.color+"18",border:`1px solid ${s.color}33`,borderRadius:7,padding:"5px 8px",flexShrink:0}}><span style={{fontSize:s.abbr.length>6?10:s.abbr.length>4?12:15,fontWeight:900,color:s.color,lineHeight:1,whiteSpace:"nowrap"}}>{s.abbr}</span></div><div style={{background:s.color+"12",color:s.color,borderRadius:20,padding:"2px 7px",fontSize:9,fontWeight:700,letterSpacing:"0.07em",textTransform:"uppercase",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{s.tag}</div></div><div style={{fontSize:11,fontWeight:600,color:"#F0EDE6",lineHeight:1.4,wordBreak:"break-word"}}>{s.name}</div><div style={{fontSize:10,color:"rgba(240,237,230,0.4)",lineHeight:1.5}}>{s.desc}</div><div style={{fontSize:9,color:s.color+"99",fontFamily:"monospace",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{s.url}</div></div>);}
function SourceTicker({setPage}){const trackRef=useRef(null),animRef=useRef(null),posRef=useRef(0),speedRef=useRef(0.5);const doubled=[...SOURCES,...SOURCES];useEffect(()=>{const track=trackRef.current;if(!track)return;const sw=track.scrollWidth/2;const animate=()=>{posRef.current-=speedRef.current;if(Math.abs(posRef.current)>=sw)posRef.current=0;track.style.transform=`translateX(${posRef.current}px)`;animRef.current=requestAnimationFrame(animate);};animRef.current=requestAnimationFrame(animate);return()=>cancelAnimationFrame(animRef.current);},[]);return(<div style={{background:"#0f1e2d",borderTop:"1px solid rgba(240,237,230,0.05)",borderBottom:"1px solid rgba(240,237,230,0.05)",padding:"48px 0",marginTop:64}}><div style={{textAlign:"center",marginBottom:32,padding:"0 24px"}}><div style={{fontSize:10,letterSpacing:"0.16em",textTransform:"uppercase",color:"rgba(240,237,230,0.28)",marginBottom:8,fontWeight:600}}>Built on authoritative data</div><h2 style={{fontSize:"clamp(16px,3vw,26px)",fontWeight:800,letterSpacing:"-0.02em",margin:"0 0 8px"}}>Data you can trust</h2><p style={{fontSize:13,color:"rgba(240,237,230,0.38)",maxWidth:440,margin:"0 auto",lineHeight:1.65}}>Every number on this site is derived from government, regulatory, and institutional sources.</p></div><div style={{position:"relative"}}><div style={{overflow:"hidden"}} onMouseEnter={()=>speedRef.current=0} onMouseLeave={()=>speedRef.current=0.5}><div ref={trackRef} style={{display:"flex",gap:10,width:"max-content",willChange:"transform",padding:"0 12px"}}>{doubled.map((s,i)=><SourceBadge key={i} s={s}/>)}</div></div><div style={{position:"absolute",left:0,top:0,bottom:0,width:80,background:"linear-gradient(90deg,#0f1e2d,transparent)",pointerEvents:"none"}}/><div style={{position:"absolute",right:0,top:0,bottom:0,width:80,background:"linear-gradient(270deg,#0f1e2d,transparent)",pointerEvents:"none"}}/></div><div style={{display:"flex",justifyContent:"center",gap:40,marginTop:28,flexWrap:"wrap",padding:"0 24px"}}>{[{val:"9",label:"official sources"},{val:"2-yearly",label:"ABS data cycle"},{val:"Quarterly",label:"ASFA updates"},{val:"Monthly",label:"APRA & CoreLogic"}].map(s=><div key={s.label} style={{textAlign:"center"}}><div style={{fontSize:16,fontWeight:800,color:"#E8935A",marginBottom:2}}>{s.val}</div><div style={{fontSize:11,color:"rgba(240,237,230,0.3)"}}>{s.label}</div></div>)}</div><div style={{textAlign:"center",marginTop:20}}><button style={{background:"transparent",border:"none",color:"rgba(240,237,230,0.3)",fontSize:12,cursor:"pointer",textDecoration:"underline",textDecorationColor:"rgba(240,237,230,0.15)"}} onClick={()=>setPage("about")}>Full methodology on the About the Data page</button></div></div>);}
function Bell({percentile,animated,color="#E8935A"}){
  const ref=useRef(null),ar=useRef(null);const [dp,setDp]=useState(0);
  useEffect(()=>{if(!animated){setDp(percentile);return;}let s=null;const ease=t=>t<0.5?2*t*t:-1+(4-2*t)*t;const run=ts=>{if(!s)s=ts;const p=Math.min((ts-s)/1200,1);setDp(Math.round(ease(p)*percentile));if(p<1)ar.current=requestAnimationFrame(run);};ar.current=requestAnimationFrame(run);return()=>cancelAnimationFrame(ar.current);},[percentile,animated]);
  useEffect(()=>{const c=ref.current;if(!c)return;const ctx=c.getContext("2d"),W=c.width,H=c.height;ctx.clearRect(0,0,W,H);const mu=0.5,si=0.18,g=x=>Math.exp(-0.5*((x-mu)/si)**2),my=g(mu),n=300;const mX=(dp/100)*(W-60)+30;ctx.beginPath();for(let i=0;i<=n;i++){const x=(i/n)*(W-60)+30,t=i/n,y=H-30-(g(t)/my)*(H-60);if(i===0)ctx.moveTo(x,H-30);ctx.lineTo(x,y);if(x>=mX)break;}ctx.lineTo(mX,H-30);ctx.closePath();const gr=ctx.createLinearGradient(30,0,mX,0);gr.addColorStop(0,color+"26");gr.addColorStop(1,color+"80");ctx.fillStyle=gr;ctx.fill();ctx.beginPath();for(let i=0;i<=n;i++){const x=(i/n)*(W-60)+30,t=i/n,y=H-30-(g(t)/my)*(H-60);i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);}ctx.strokeStyle="rgba(240,237,230,0.2)";ctx.lineWidth=2;ctx.stroke();ctx.beginPath();ctx.moveTo(30,H-30);ctx.lineTo(W-30,H-30);ctx.strokeStyle="rgba(240,237,230,0.12)";ctx.lineWidth=1;ctx.stroke();ctx.fillStyle="rgba(240,237,230,0.3)";ctx.font="11px system-ui";ctx.textAlign="center";[0,25,50,75,100].forEach(p=>ctx.fillText(p+"%",(p/100)*(W-60)+30,H-10));const mT=(mX-30)/(W-60),mY=H-30-(g(mT)/my)*(H-60);ctx.beginPath();ctx.moveTo(mX,H-30);ctx.lineTo(mX,mY-10);ctx.strokeStyle=color;ctx.lineWidth=2;ctx.setLineDash([4,3]);ctx.stroke();ctx.setLineDash([]);ctx.beginPath();ctx.arc(mX,mY-10,6,0,Math.PI*2);ctx.fillStyle=color;ctx.fill();ctx.beginPath();ctx.arc(mX,mY-10,3,0,Math.PI*2);ctx.fillStyle="#fff";ctx.fill();},[dp,color]);
  return <canvas ref={ref} width={600} height={180} style={{width:"100%",height:"auto",display:"block"}}/>;
}
function AmbientCurve(){
  const ref=useRef(null);
  useEffect(()=>{const c=ref.current;if(!c)return;const ctx=c.getContext("2d"),W=c.width,H=c.height;ctx.clearRect(0,0,W,H);const mu=0.5,si=0.2,g=x=>Math.exp(-0.5*((x-mu)/si)**2),my=g(mu),n=400;const gr=ctx.createLinearGradient(0,0,W,0);gr.addColorStop(0,"rgba(232,147,90,0)");gr.addColorStop(0.5,"rgba(232,147,90,0.07)");gr.addColorStop(1,"rgba(232,147,90,0)");ctx.beginPath();for(let i=0;i<=n;i++){const x=(i/n)*W,t=i/n,y=H-(g(t)/my)*(H*0.82);i===0?ctx.moveTo(x,H):ctx.lineTo(x,y);}ctx.lineTo(W,H);ctx.closePath();ctx.fillStyle=gr;ctx.fill();ctx.beginPath();for(let i=0;i<=n;i++){const x=(i/n)*W,t=i/n,y=H-(g(t)/my)*(H*0.82);i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);}ctx.strokeStyle="rgba(232,147,90,0.15)";ctx.lineWidth=1.5;ctx.stroke();},[]);
  return <canvas ref={ref} width={900} height={160} style={{position:"absolute",bottom:0,left:0,width:"100%",height:"auto",pointerEvents:"none",opacity:0.8}}/>;
}
function CountUp({to}){const [v,setV]=useState(0);const r=useRef(null);useEffect(()=>{let s=null;const run=ts=>{if(!s)s=ts;const p=Math.min((ts-s)/2000,1),e=1-Math.pow(1-p,3);setV(Math.round(e*to));if(p<1)r.current=requestAnimationFrame(run);};r.current=requestAnimationFrame(run);return()=>cancelAnimationFrame(r.current);},[to]);return <span>${v>=1000000?(v/1000000).toFixed(1)+"M":Math.round(v/1000)+"K"}</span>;}
function WhatIf({nw,age,accent}){
  const [mo,setMo]=useState(500);const [rate,setRate]=useState(7);
  const proj=y=>{const r=rate/100,c=mo*12;return nw*Math.pow(1+r,y)+(r>0?c*((Math.pow(1+r,y)-1)/r):c*y);};
  const mx=Math.max(proj(10),proj(20),proj(30));
  return(<div style={{background:"#142133",border:"1px solid rgba(240,237,230,0.08)",borderRadius:16,padding:"20px",marginBottom:16}}>
    <div style={{fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",color:"rgba(240,237,230,0.3)",marginBottom:12}}>What-If Simulator</div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:16}}>
      <div><div style={{fontSize:10,color:"rgba(240,237,230,0.35)",textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:5}}>Monthly investment</div><div style={{display:"flex",alignItems:"center",gap:8}}><input type="range" min={0} max={5000} step={100} value={mo} onChange={e=>setMo(+e.target.value)} style={{flex:1,accentColor:accent}}/><span style={{fontSize:12,fontWeight:700,minWidth:55,textAlign:"right"}}>{fmt(mo)}/mo</span></div></div>
      <div><div style={{fontSize:10,color:"rgba(240,237,230,0.35)",textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:5}}>Annual growth</div><div style={{display:"flex",alignItems:"center",gap:8}}><input type="range" min={1} max={12} step={0.5} value={rate} onChange={e=>setRate(+e.target.value)} style={{flex:1,accentColor:accent}}/><span style={{fontSize:12,fontWeight:700,minWidth:30,textAlign:"right"}}>{rate}%</span></div></div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
      {[10,20,30].map(y=>{const v=proj(y),h=Math.round((v/mx)*64);return(<div key={y} style={{background:"rgba(13,27,42,0.5)",borderRadius:10,padding:"12px 8px",textAlign:"center"}}><div style={{height:64,display:"flex",alignItems:"flex-end",justifyContent:"center",marginBottom:5}}><div style={{width:28,background:accent,borderRadius:"3px 3px 0 0",height:h,opacity:0.85,transition:"height 0.4s"}}/></div><div style={{fontSize:10,color:"rgba(240,237,230,0.3)",marginBottom:2}}>{y} years</div><div style={{fontSize:13,fontWeight:700}}>{fmt(v)}</div><div style={{fontSize:10,color:"#5BA08A"}}>+{fmt(v-nw)}</div></div>);})}
    </div>
  </div>);
}
const TOOL_PAGES=["calculator","income","super","forecast","fire"];
function Nav({page,setPage}){
  const pages=[{id:"home",l:"Home"},{id:"tools",l:"Tools"},{id:"gen",l:"By Generation"},{id:"insights",l:"Insights"},{id:"about",l:"About the Data"}];
  const toolActive=TOOL_PAGES.includes(page);
  const [open,setOpen]=useState(false);
  const close=()=>setOpen(false);
  const go=(id)=>{setPage(id);close();};
  return(
    <nav style={{position:"sticky",top:0,zIndex:100,background:"rgba(13,27,42,0.96)",backdropFilter:"blur(12px)",borderBottom:"1px solid rgba(240,237,230,0.07)",padding:"0 20px",display:"flex",alignItems:"center",justifyContent:"space-between",height:56}}>
      <div style={{fontWeight:800,fontSize:15,letterSpacing:"-0.01em",cursor:"pointer",display:"flex",alignItems:"center",gap:7}} onClick={()=>go("home")}>
        Wealth<span style={{color:"#E8935A"}}>Rank</span><span style={{fontSize:10,color:"rgba(240,237,230,0.3)",marginLeft:3,fontWeight:400}}>AU</span>
        <span style={{fontSize:9,background:"rgba(91,160,138,0.12)",color:"#5BA08A",border:"1px solid rgba(91,160,138,0.2)",borderRadius:4,padding:"2px 5px",fontWeight:600}}>v1.5</span>
      </div>
      {/* Desktop nav */}
      <div className="nav-desktop" style={{display:"flex",gap:2}}>
        {pages.map(p=>{const active=p.id==="tools"?toolActive:page===p.id;return(<button key={p.id} onClick={()=>go(p.id)} style={{padding:"5px 10px",border:"none",background:active?"rgba(232,147,90,0.12)":"transparent",color:active?"#E8935A":"rgba(240,237,230,0.45)",borderRadius:7,fontSize:12,fontWeight:active?700:400,cursor:"pointer"}}>{p.l}</button>);})}
      </div>
      {/* Hamburger — visible on small screens via inline media workaround */}
      <button
        onClick={()=>setOpen(o=>!o)}
        style={{display:"none",background:"none",border:"none",cursor:"pointer",padding:"6px",color:"rgba(240,237,230,0.7)",flexDirection:"column",gap:4,alignItems:"center",justifyContent:"center"}}
        className="nav-hamburger"
        aria-label="Menu"
      >
        <span style={{display:"block",width:20,height:2,background:"currentColor",borderRadius:2,transition:"all 0.2s",transform:open?"rotate(45deg) translate(4px,4px)":"none"}}/>
        <span style={{display:"block",width:20,height:2,background:"currentColor",borderRadius:2,transition:"all 0.2s",opacity:open?0:1}}/>
        <span style={{display:"block",width:20,height:2,background:"currentColor",borderRadius:2,transition:"all 0.2s",transform:open?"rotate(-45deg) translate(4px,-4px)":"none"}}/>
      </button>
      {/* Mobile dropdown */}
      {open&&(
        <div style={{position:"fixed",top:56,left:0,right:0,bottom:0,zIndex:99}}>
          <div style={{position:"absolute",inset:0,background:"rgba(13,27,42,0.5)"}} onClick={close}/>
          <div style={{position:"absolute",top:0,left:0,right:0,background:"rgba(13,27,42,0.98)",borderBottom:"1px solid rgba(240,237,230,0.07)",padding:"8px 16px 16px"}}>
            {pages.map(p=>{const active=p.id==="tools"?toolActive:page===p.id;return(
              <button key={p.id} onClick={()=>go(p.id)} style={{display:"block",width:"100%",textAlign:"left",padding:"13px 12px",border:"none",borderBottom:"1px solid rgba(240,237,230,0.05)",background:"none",color:active?"#E8935A":"rgba(240,237,230,0.65)",fontSize:15,fontWeight:active?700:400,cursor:"pointer",borderRadius:0}}>
                {p.l}
              </button>
            );})}
          </div>
        </div>
      )}
    </nav>
  );
}
